css:
.loader {color: var(--loader-color, #6d28d9);
  --loader-secondary-color: #f0abfc;
  --loader-bg: #ffffff;
   width: 16px;
   aspect-ratio: 1;
   background: var(--loader-color, #6d28d9);
   box-shadow: 0 -16px var(--loader-secondary-color, #f0abfc);
   animation: l6 2s infinite;
}
@keyframes l6  {
  0% {transform: translate(0 ,0 ) rotate(0)}
25% {transform: translate(0 ,0 ) rotate(90deg)}
50% {transform: translate(100%,-100%) rotate(180deg)}
75% {transform: translate(100%,-100%) rotate(270deg)}
100% {transform: translate(0 ,0 ) rotate(360deg)}
}
